function solve(nums, digit) {
    let totalCount = 0;
    const digitStr = String(digit);

    for (const num of nums) {
        const numStr = String(num);
        let count = 0;
        for (let i = 0; i < numStr.length; i++) {
            if (numStr[i] === digitStr) {
                count++;
            }
        }
        totalCount += count;
    }

    return totalCount;
}

